content:
求下列微分方程满足所给条件的特解：
    \begin{enumerate}
        \item $x y\mathrm{d}x + (x + 1)\mathrm{d}y = 0,\ y(1) = 2$;
        \item $(x^{2} - 1)y^{\prime} + 2x y^{2} = 0,\ y(0) = 1$;
        \item $x y^{\prime} + y = y^{2},\ y(1) = \frac{1}{2}$;
        \item $y^{\prime} = \sqrt{4x + 2y - 1},\ y(0) = 1$;
        \item $(x + 2y)y^{\prime} = 1,\ y(0) = -1$;
        \item $x^{2}y^{\prime} - \cos 2y = 1,\ y(+\infty) = \frac{9\pi}{4}$;
        \item $3y^{2}y^{\prime} + 16x = 2xy^{3}$，当 $x \rightarrow +\infty$ 时，$y(x)$ 有界.
    \end{enumerate}

求解下列微分方程，并作出积分曲线的草图：
    \begin{enumerate}
        \item $y^{\prime} = a y$，其中 $a$ 是不为零的常数；
        \item $y^{\prime} = y^{a}$，其中 $a = \frac{1}{5},1,2$.
    \end{enumerate}

求解下列微分方程：
    \begin{enumerate}
        \item $x y^{\prime} - 2y = 2x^{4}$;
        \item $(2x + 1)y^{\prime} = 4x + 2y$;
        \item $(x y + \mathrm{e}^{x})\mathrm{d}x - x\mathrm{d}y = 0$;
        \item $2x(x^{2} + y)\mathrm{d}x = \mathrm{d}y$;
        \item $(1 - 2x y)y^{\prime} = y(y - 1)$.
    \end{enumerate}

求下列微分方程的解：
    \begin{enumerate}
        \item $(x^{2} + y^{2} + x)\mathrm{d}x + y\mathrm{d}y = 0$;
        \item $(x^{2} + y^{2} + y)\mathrm{d}x - x\mathrm{d}y = 0$;
        \item $y\mathrm{d}y = (x\mathrm{d}y + y\mathrm{d}x)\sqrt{1 + y^{2}}$;
        \item $y^{2}\mathrm{d}x - (xy + x^{3})\mathrm{d}y = 0$;
        \item $y\mathrm{d}x - x\mathrm{d}y = 2x^{3}\tan {\frac{y}{x}}\mathrm{d}x$;
        \item $x y\mathrm{d}x = (y^{3} + x^{2}y + x^{2})\mathrm{d}y$;
        \item $(x^{2} - y^{2} + y)\mathrm{d}x + x(2y - 1)\mathrm{d}y = 0$;
        \item $y^{2}(y\mathrm{d}x - 2x\mathrm{d}y) = x^{3}(x\mathrm{d}y - 2y\mathrm{d}x)$.
    \end{enumerate}

证明：方程(2.18)有形如 $\mu = \mu (\phi (x,y))$ 的积分因子的充要条件是
    \[
    \frac{\frac{\partial P}{\partial y} - \frac{\partial Q}{\partial x}}{Q\frac{\partial\phi}{\partial x} - P\frac{\partial\phi}{\partial y}} = f(\phi (x,y)),
    \]
    其中 $f$ 为某个一元函数。应用这一结果，给出存在下列类型的积分因子的充要条件：
    \begin{enumerate}
        \item $\mu = \mu (x \pm y)$;
        \item $\mu = \mu (x^{2} + y^{2})$;
        \item $\mu = \mu (xy)$;
        \item $\mu = \mu (x^{\alpha} y^{\beta})$ ($\alpha, \beta$ 为常数).
    \end{enumerate}

求解下列微分方程：
    \begin{enumerate}
        \item $8y^{\prime 3}=27y$;
        \item $y^{\prime 2}+x y=y^{2}+x y^{\prime}$;
        \item $y+x y^{\prime}=4\sqrt{y^{\prime}}$.
    \end{enumerate}

利用参数法求解下列微分方程：
    \begin{enumerate}
        \item $2x y^{\prime}-y=y^{\prime}\ln(y y^{\prime})$;
        \item $y^{\prime 2}-2x y^{\prime}=x^{2}-4y$.
    \end{enumerate}

对于怎样的 $a$，下列微分方程的每个解都能延伸到无穷区间 $(- \infty , + \infty)$ 上？
    \begin{enumerate}
        \item $y' = y^a \sin y$;
        \item $y' = y^2 + a$.
    \end{enumerate}

假设函数 $f(x,y)$ 在闭区域 $0\leqslant x\leqslant a, - \infty < y< +\infty$ 上连续。记 $\phi (x,\xi)$ 是微分方程 $y^{\prime} = f(x,y)$ 满足初始条件 $\phi (0,\xi) = \xi$ 的解。进一步，假设 $\phi (x,\xi)$ 在区间 $[0,\bar{x})$ 上存在，$\bar{x}< a$。证明下列三个结论之一成立：
    \begin{enumerate}
        \item $\lim_{x\to \bar{x} - 0}\phi (x,\xi)$ 有限，此时解 $y = \phi (x,\xi)$ 可以延伸至 $x = \bar{x}$；
        \item $\lim_{x\to \bar{x} - 0}\phi (x,\xi) = +\infty$；
        \item $\lim_{x\to \bar{x} - 0}\phi (x,\xi) = -\infty$。
    \end{enumerate}

已知微分方程的通解如下 ($c$ 为任意常数)，求出微分方程的解：
    \begin{enumerate}
        \item $y = c x^{2} - c^{2}$;
        \item $y = c(x - c)^{2}$;
        \item $y = c(x + c)^{2}$;
        \item $y = \frac{1}{2} c(x + c)^{2}$;
        \item $y = \frac{1}{2} c^{2} + c^{2}$;
        \item $y = \frac{1}{2} c^{2} + c$;
    \end{enumerate}

求给定微分方程初值问题的解对初值或参数的导数：
    \begin{enumerate}
        \item $y' = x + y + \lambda y^2, \ y(0) = 0$，求 $\left.\frac{\partial y}{\partial \lambda}\right|_{\lambda = 0}$；
        \item $y' = x^2 + \mu y^3, \ y(0) = 1$，求 $\left.\frac{\partial y}{\partial \mu}\right|_{\mu = 0}$。
    \end{enumerate}

求解微分方程 $\frac{\mathrm{d}y}{\mathrm{d}x} = A y$，其中矩阵 $A$ 如下：
    \begin{enumerate}
        \item $A = \begin{pmatrix} 2 & 1 \\ 3 & 4 \end{pmatrix}$;
        \item $A = \begin{pmatrix} 1 & -1 \\ -4 & 1 \end{pmatrix}$;
        \item $A = \begin{pmatrix} 1 & 2 & -1 \\ 2 & 1 & -1 \\ 1 & -1 & 2 \end{pmatrix}$;
        \item $A = \begin{pmatrix} 1 & -1 & -1 \\ 1 & 1 & 0 \\ 3 & 0 & 1 \end{pmatrix}$;
        \item $A = \begin{pmatrix} 4 & -1 & -1 \\ 1 & 2 & -1 \\ 1 & -1 & 2 \end{pmatrix}$;
        \item $A = \begin{pmatrix} 2 & -1 & -1 \\ 3 & -2 & -3 \\ -1 & 1 & 2 \end{pmatrix}$;
        \item $A = \begin{pmatrix} 0 & 1 & 0 \\ 0 & 0 & 1 \\ 1 & -3 & 3 \end{pmatrix}$;
        \item $A = \begin{pmatrix} 1 & 2 & 2 \\ 2 & 1 & 2 \\ 2 & 2 & 1 \end{pmatrix}$.
    \end{enumerate}

求解下列非齐次线性微分方程组：
    \begin{enumerate}
        \item $\frac{\mathrm{d}x}{\mathrm{d}t} = x + 2y + e^t,\ \frac{\mathrm{d}y}{\mathrm{d}t} = 2x + y + e^{2t}$;
        \item $\frac{\mathrm{d}x}{\mathrm{d}t} = 2x - y + z,\ \frac{\mathrm{d}y}{\mathrm{d}t} = x + z,\ \frac{\mathrm{d}z}{\mathrm{d}t} = -x + y + 2z + e^t$;
        \item $\frac{\mathrm{d}x}{\mathrm{d}t} = 3x - y + z,\ \frac{\mathrm{d}y}{\mathrm{d}t} = x + y + z,\ \frac{\mathrm{d}z}{\mathrm{d}t} = 4x - y + 4z + 3e^t$.
    \end{enumerate}

利用常数变易法求解下列非齐次线性微分方程组：
    \begin{enumerate}
        \item $\frac{\mathrm{d}x}{\mathrm{d}t} = y + \tan^2 t - 1,\ \frac{\mathrm{d}y}{\mathrm{d}t} = -x + \tan t$;
        \item $\frac{\mathrm{d}x}{\mathrm{d}t} = y - z + \cos t,\ \frac{\mathrm{d}y}{\mathrm{d}t} = -x + \sin t,\ \frac{\mathrm{d}z}{\mathrm{d}t} = 2y - z$.
    \end{enumerate}

求解下列微分方程：
    \begin{enumerate}
        \item $y'' + y' - 2y = 0$;
        \item $y'' + 4y = 0$;
        \item $y^{(4)} - 5y'' + 4y = 0$;
        \item $y'' + y = 4\sin x$;
        \item $y'' - 4y' + 8y = e^{2x} + \sin 2x$;
        \item $y'' - 2y' + y = 6x e^x$;
        \item $y'' - 6y' + 8y = 5x e^{4x} + 2e^{4x} \sin x$.
    \end{enumerate}

利用常数变易法求解下列微分方程：
    \begin{enumerate}
        \item $y'' - 2y' + y = x^{-1} e^x$;
        \item $y'' + 4y = 2\tan x$;
        \item $y'' - y = x^{-1} - 2x^{-3}$.
    \end{enumerate}

求下列微分方程在 $x = x_0$ 处的两个线性无关解：
    \begin{enumerate}
        \item $y'' - x y' - y = 0,\ x_0 = 0$;
        \item $y'' - x y' - y = 0,\ x_0 = 1$.
    \end{enumerate}

判别 $x = -1, 0, 1$ 是下列微分方程的什么点（常点、正则奇点或非正则奇点）：
    \begin{enumerate}
        \item $x y'' + (1 - x) y' + x y = 0$;
        \item $2x^2(1 - x^2) y'' + 2x y' + 3x^2 y = 0$;
        \item $x^2(1 - x^2) y'' + 2x^{-1} y' + 4y = 0$.
    \end{enumerate}

利用广义幂级数求解下列微分方程：
    \begin{enumerate}
        \item $2x y'' + y' + x y = 0$;
        \item $x y'' + y' - y = 0$.
    \end{enumerate}

求解边值问题：
    \begin{enumerate}
        \item $y'' + y = 0, \quad y(0) = 0, \ y(1) = 0$;
        \item $y'' + y = 0, \quad y'(0) = 0, \ y'(1) = 0$.
    \end{enumerate}

设群 G 中两个元 g, h 可换, \(o(g) = m\), \(o(h) = n\). 记 \((m, n)\), \([m, n]\) 分别是 m, n 的最大公因子和最小公倍数. 则
\[
o(g^{n}h^{m}) = \frac{[m, n]}{(m, n)};
\]
(2) G 中存在阶为 \((m, n)\) 的元;
(3) G 中存在阶为 \([m, n]\) 的元.
